-module(bignum).
-export([tostr/0, cmp/0, lit/0, neg/0, abs1/0]).
tostr() -> integer_to_binary(1000000000000000000 * 100).
cmp() -> 1000000000000000000 * 100 =:= 100000000000000000000.
lit() -> 100000000000000000000.
neg() -> -(1000000000000000000 * 100).
abs1() -> abs(-(1000000000000000000 * 100)).
